import{_ as r,o as i,c as a,ae as d}from"./chunks/framework.Czhw_PXq.js";const g=JSON.parse('{"title":"Notemd 图形渲染平台路线图","description":"","frontmatter":{},"headers":[],"relativePath":"superpowers/plans/2026-04-14-diagram-rendering-platform-roadmap.zh-CN.md","filePath":"superpowers/plans/2026-04-14-diagram-rendering-platform-roadmap.zh-CN.md"}'),t={name:"superpowers/plans/2026-04-14-diagram-rendering-platform-roadmap.zh-CN.md"};function o(l,e,c,s,n,m){return i(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="notemd-图形渲染平台路线图" tabindex="-1">Notemd 图形渲染平台路线图 <a class="header-anchor" href="#notemd-图形渲染平台路线图" aria-label="Permalink to &quot;Notemd 图形渲染平台路线图&quot;">​</a></h1><blockquote><p><strong>给代理执行者：</strong> 必须使用 <code>superpowers:subagent-driven-development</code>（推荐）或 <code>superpowers:executing-plans</code>，按任务逐步执行本计划。步骤继续使用复选框 <code>- [ ]</code> 语法跟踪。</p></blockquote><p><strong>目标：</strong> 将 Notemd 从“LLM 直接生成 Mermaid 文本并事后修补”的单一路径，升级为“图形意图识别 + 中间规格 + 专门渲染 + 多格式输出”的可扩展图形平台，在 Obsidian 内稳定支持更多图像与图表类型。</p><p><strong>架构：</strong> 采用四层架构：<code>Intent Plane</code> 负责识别笔记更适合的图形表达；<code>Spec Plane</code> 让 LLM 输出结构化 <code>DiagramSpec</code> 而不是直接输出语法；<code>Adapter Plane</code> 负责不同目标格式的生成、校验与最小修复；<code>Rendering Plane</code> 提供专门渲染宿主、缓存、预览、主题和导出能力。该方案有意避免把 <code>markdown-viewer</code> 整体照抄进 Notemd，而是吸收其 registry/host/cache 思想，并按 Obsidian 插件约束做渐进式落地。</p><p><strong>技术栈：</strong> TypeScript、Obsidian Plugin API、Mermaid、Jest、ESLint、esbuild、基于 iframe 的渲染宿主、JSON Canvas、Vega-Lite、SVG/HTML 预览链路</p><hr><h2 id="执行状态-2026-04-14" tabindex="-1">执行状态（2026-04-14） <a class="header-anchor" href="#执行状态-2026-04-14" aria-label="Permalink to &quot;执行状态（2026-04-14）&quot;">​</a></h2><p>这份路线图现在不再只是“待实现计划”。<code>main</code> 已经落地了 diagram domain model、spec-first 生成、Mermaid subtype adapters、renderer registry/service、JSON Canvas、Vega-Lite、preview/export、theme/i18n 等核心能力，但文档状态没有及时跟上，容易导致两种误判：</p><ul><li>把已经存在的能力当成未开始，重复设计</li><li>把仍处于 experimental / partial 状态的边界当成已完成能力，对后续发布和架构判断形成误导</li></ul><p>本次更新的目标不是改写方向，而是把 roadmap 变成“真实进度文档 + 下一批推进控制器”。</p><p>Phase-2 需求快照：</p><ul><li><code>docs/brainstorms/2026-04-14-diagram-platform-phase-2-requirements.md</code></li></ul><h3 id="当前快照" tabindex="-1">当前快照 <a class="header-anchor" href="#当前快照" aria-label="Permalink to &quot;当前快照&quot;">​</a></h3><table tabindex="0"><thead><tr><th>任务</th><th>状态</th><th>当前现实</th></tr></thead><tbody><tr><td>任务 0</td><td>已交付，但限制已明确</td><td><code>src/rendering/webview/*</code> 与 <code>src/rendering/host/iframeRenderHost.ts</code> 已落地，继续采用内联 <code>srcdoc</code> 方案；<code>scripts/audit-render-host-bundle.js</code>、release workflow 与单测已把“render host 必须由 <code>main.js</code> 自包含携带”的 smoke gate 固化下来，但 <code>esbuild.config.mjs</code> 仍是单入口，真正的 heavier-runtime isolation 仍未完成。</td></tr><tr><td>任务 1</td><td>已交付</td><td><code>DiagramIntent</code>、<code>DiagramSpec</code>、validator、planner 和意图推断规则均已进入主线，并有单测覆盖。</td></tr><tr><td>任务 2</td><td>部分完成</td><td>spec-first prompt 与 service pipeline 已落地，<code>src/main.ts</code> 也新增了共享 <code>generateDiagramCommand</code> 执行器，并把 legacy Mermaid 保存、experimental save、experimental preview 三条命令收口到同一 orchestration path；但 public command surfaces 仍保留兼容双轨，真正的 surface-level command architecture 收口尚未完成。</td></tr><tr><td>任务 3</td><td>部分完成</td><td>Mermaid subtype adapters 与 <code>mermaid.parse</code> 校验已落地，flowchart pipe-label escaping 已前移到 adapter emit，legacy note directive parsing / edge-attachment / note-node formatting 与一批 edge-label merge/quote/rewrite helper 也已开始下沉到 <code>src/diagram/adapters/mermaid/legacyFixerUtils.ts</code>；但 <code>src/mermaidProcessor.ts</code> 仍承担大量 legacy fixer 责任，adapter-driven fixer 拆分未完成。</td></tr><tr><td>任务 4</td><td>已交付</td><td>renderer registry/service、cache、inline host、iframe preview session 与统一 preview modal 已落地。</td></tr><tr><td>任务 5</td><td>已交付</td><td><code>.canvas</code> 输出、基础 deterministic layout、保存与预览链路已落地。</td></tr><tr><td>任务 6</td><td>部分完成</td><td>Vega-Lite controlled templates、planner chart defaults、preview/export 已落地，但“通过 iframe host 隔离渲染依赖”这一目标仍未完全成立。</td></tr><tr><td>任务 7</td><td>已交付，但限制已明确</td><td>主题、locale、SVG/PNG/source export 和文档矩阵已对齐当前代码；HTML 目标仍只承诺 iframe fallback preview 与 raw source save。</td></tr><tr><td>任务 8</td><td>按设计延后</td><td>高级 DSL / renderer 评估仍应继续推迟。</td></tr></tbody></table><h3 id="证据索引" tabindex="-1">证据索引 <a class="header-anchor" href="#证据索引" aria-label="Permalink to &quot;证据索引&quot;">​</a></h3><ul><li>spec-first 领域层： <ul><li><code>src/diagram/types.ts</code></li><li><code>src/diagram/intent.ts</code></li><li><code>src/diagram/spec.ts</code></li><li><code>src/diagram/planner.ts</code></li><li><code>src/diagram/diagramGenerationService.ts</code></li></ul></li><li>Mermaid 子类型适配器： <ul><li><code>src/diagram/adapters/mermaid/mindmapAdapter.ts</code></li><li><code>src/diagram/adapters/mermaid/flowchartAdapter.ts</code></li><li><code>src/diagram/adapters/mermaid/sequenceAdapter.ts</code></li><li><code>src/diagram/adapters/mermaid/classAdapter.ts</code></li><li><code>src/diagram/adapters/mermaid/erAdapter.ts</code></li><li><code>src/diagram/adapters/mermaid/stateAdapter.ts</code></li><li><code>src/diagram/adapters/mermaid/validator.ts</code></li></ul></li><li>渲染平台： <ul><li><code>src/rendering/rendererRegistry.ts</code></li><li><code>src/rendering/rendererService.ts</code></li><li><code>src/rendering/cache/renderCache.ts</code></li><li><code>src/rendering/host/inlineRenderHost.ts</code></li><li><code>src/rendering/host/iframeRenderHost.ts</code></li><li><code>scripts/audit-render-host-bundle.js</code></li><li><code>.github/workflows/release.yml</code></li><li><code>src/ui/DiagramPreviewModal.ts</code></li></ul></li><li>非 Mermaid 目标： <ul><li><code>src/diagram/adapters/canvas/canvasAdapter.ts</code></li><li><code>src/diagram/adapters/vega/vegaLiteAdapter.ts</code></li><li><code>src/rendering/renderers/jsonCanvasRenderer.ts</code></li><li><code>src/rendering/renderers/vegaLiteRenderer.ts</code></li><li><code>src/rendering/renderers/htmlRenderer.ts</code></li></ul></li><li>已经约束当前行为的文档与测试： <ul><li><code>src/tests/diagramGenerationService.test.ts</code></li><li><code>src/tests/diagramGenerationFallbacks.test.ts</code></li><li><code>src/tests/canvasAdapter.test.ts</code></li><li><code>src/tests/vegaLiteAdapter.test.ts</code></li><li><code>src/tests/rendererService.test.ts</code></li><li><code>src/tests/diagramPreviewModal.test.ts</code></li><li><code>src/tests/previewExport.test.ts</code></li><li><code>src/tests/diagramDocsContract.test.ts</code></li><li><code>src/tests/renderHostBundleAuditScript.test.ts</code></li></ul></li></ul><h2 id="为什么需要这份计划" tabindex="-1">为什么需要这份计划 <a class="header-anchor" href="#为什么需要这份计划" aria-label="Permalink to &quot;为什么需要这份计划&quot;">​</a></h2><p>更新说明（2026-04-14）：</p><p>这部分保留了最初推动 diagram platform 改造的根因判断，但现状已经不是“这些能力完全不存在”，而是“核心能力已落地，剩余短板集中在 legacy 路径、命令收口和 runtime boundary”。下面的判断应理解为当前仍然存在的架构压力，而不是对 <code>main</code> 现状的全盘否定。</p><p>当前实现的瓶颈不是“支持的图表类型太少”，而是职责边界错误：</p><ul><li><code>src/main.ts</code> 仍然同时承载 legacy Mermaid 链路、experimental diagram 链路、命令注册和 UI 编排，diagram domain 已经存在，但尚未真正从插件入口里抽离。</li><li><code>src/promptUtils.ts</code> 中的 legacy Mermaid prompt 仍把输出强制绑死在 <code>mindmap</code>，虽然 spec-first 路径已经绕开这一问题，但命令层尚未完全收口到新路径。</li><li><code>src/mermaidProcessor.ts</code> 已经演变成巨型修补器，说明系统在用后处理复杂度弥补 prompt 和建模不足。</li><li>当前构建方式仍只有单一 <code>main.js</code> 输出，<code>esbuild.config.mjs</code> 还没有为后续更重的 iframe/webview 资产、worker 或渲染静态资源建立明确打包策略。</li></ul><p>如果继续沿着“多写几个 prompt + 多加几条 regex 修复 + 再支持几个新语法”的方向推进，复杂度会线性增长，稳定性会指数下降。</p><hr><h2 id="产品北极星" tabindex="-1">产品北极星 <a class="header-anchor" href="#产品北极星" aria-label="Permalink to &quot;产品北极星&quot;">​</a></h2><p>Notemd 的图形能力应当服务于三类核心场景，而不是追求“支持格式列表越长越好”：</p><ol><li><p>结构理解 将长文、研究笔记、技术方案转成适合浏览和回顾的结构图。</p></li><li><p>知识组织 把概念、关联、因果、层级和空间组织关系落到适合 Obsidian 工作流的可编辑载体。</p></li><li><p>数据表达 当笔记中包含指标、时间序列、对比、分布时，生成图表而不是勉强转成 Mermaid。</p></li></ol><p>对应到能力上，Notemd 需要的是“格式路由能力”，不是“单一 Mermaid 能力堆砌”。</p><hr><h2 id="仓库中的当前约束" tabindex="-1">仓库中的当前约束 <a class="header-anchor" href="#仓库中的当前约束" aria-label="Permalink to &quot;仓库中的当前约束&quot;">​</a></h2><h3 id="代码现实" tabindex="-1">代码现实 <a class="header-anchor" href="#代码现实" aria-label="Permalink to &quot;代码现实&quot;">​</a></h3><ul><li><code>src/main.ts</code> 当前承载命令注册、业务编排、legacy Mermaid 流程和 experimental diagram 流程，文件已过大，不适合作为 diagram 平台的长期 orchestration 入口。</li><li><code>src/fileUtils.ts</code> 同时负责文件保存、Mermaid 修复、批处理和错误文件移动，职责已经交叉。</li><li><code>src/mermaidProcessor.ts</code> 聚集了 Mermaid 检测、修复、语法清洗、深度 debug 等大量逻辑，应被拆分为 adapter 内的 validator/fixer。</li><li><code>src/promptUtils.ts</code> legacy prompt 仍直接绑定输出目标格式；spec-first prompt 已存在，但两套链路仍并行存在。</li></ul><h3 id="构建现实" tabindex="-1">构建现实 <a class="header-anchor" href="#构建现实" aria-label="Permalink to &quot;构建现实&quot;">​</a></h3><ul><li><code>esbuild.config.mjs</code> 仅打包 <code>src/main.ts -&gt; main.js</code>，没有静态资源复制、iframe 页面生成或多入口策略。</li><li><code>manifest.json</code> 当前为通用移动/桌面插件，不应引入只在桌面可运行的图形能力而不设降级路径。</li></ul><h3 id="测试现实" tabindex="-1">测试现实 <a class="header-anchor" href="#测试现实" aria-label="Permalink to &quot;测试现实&quot;">​</a></h3><ul><li>Jest 单测体系已经存在，适合先做 domain model、adapter、service 级测试。</li><li>当前缺失的不是测试框架，而是可测试的边界。现状里 Mermaid 生成、修复、保存耦合过深，导致只能测结果，难测职责。</li></ul><hr><h2 id="架构决策摘要" tabindex="-1">架构决策摘要 <a class="header-anchor" href="#架构决策摘要" aria-label="Permalink to &quot;架构决策摘要&quot;">​</a></h2><h3 id="决策-1-先建-diagramspec-停止让-llm-直接输出最终渲染语法" tabindex="-1">决策 1：先建 <code>DiagramSpec</code>，停止让 LLM 直接输出最终渲染语法 <a class="header-anchor" href="#决策-1-先建-diagramspec-停止让-llm-直接输出最终渲染语法" aria-label="Permalink to &quot;决策 1：先建 `DiagramSpec`，停止让 LLM 直接输出最终渲染语法&quot;">​</a></h3><p>推荐引入统一中间表示：</p><ul><li><code>DiagramIntent</code></li><li><code>DiagramSpec</code></li><li><code>RenderTarget</code></li><li><code>RenderArtifact</code></li></ul><p><code>DiagramSpec</code> 至少覆盖：</p><ul><li>title</li><li>summary</li><li>nodes</li><li>edges</li><li>sections</li><li>callouts</li><li>dataSeries</li><li>layoutHints</li><li>sourceLanguage</li><li>outputLanguage</li><li>evidenceRefs</li></ul><p>理由：</p><ul><li>可以把“内容理解”和“目标格式语法”解耦。</li><li>可以为 Mermaid、Canvas、Vega-Lite 复用同一份语义输入。</li><li>可以把校验前移到结构层，而不是等字符串生成后再补洞。</li></ul><h3 id="决策-2-先做-rendererregistry-renderhost-不要直接堆第三方引擎" tabindex="-1">决策 2：先做 <code>RendererRegistry + RenderHost</code>，不要直接堆第三方引擎 <a class="header-anchor" href="#决策-2-先做-rendererregistry-renderhost-不要直接堆第三方引擎" aria-label="Permalink to &quot;决策 2：先做 `RendererRegistry + RenderHost`，不要直接堆第三方引擎&quot;">​</a></h3><p>推荐最小平台能力：</p><ul><li><code>RendererRegistry</code></li><li><code>RendererService</code></li><li><code>RenderHost</code> interface</li><li><code>InlineRenderHost</code> 或 <code>IframeRenderHost</code></li><li><code>RenderCache</code></li></ul><p>理由：</p><ul><li>没有统一宿主时，多格式支持只会沦为“生成不同代码块文本”，不能预览、不能导出、不能缓存、不能统一主题。</li><li><code>markdown-viewer-extension</code> 真正值得借鉴的是 renderer registry、host abstraction、theme 和 cache，而不是“支持十几种格式”这件事本身。</li></ul><h3 id="决策-3-第一波扩展目标不是-plantuml-而是-mermaid-子类型-json-canvas-vega-lite" tabindex="-1">决策 3：第一波扩展目标不是 PlantUML，而是 Mermaid 子类型 + JSON Canvas + Vega-Lite <a class="header-anchor" href="#决策-3-第一波扩展目标不是-plantuml-而是-mermaid-子类型-json-canvas-vega-lite" aria-label="Permalink to &quot;决策 3：第一波扩展目标不是 PlantUML，而是 Mermaid 子类型 + JSON Canvas + Vega-Lite&quot;">​</a></h3><p>优先级如下：</p><table tabindex="0"><thead><tr><th>优先级</th><th>目标</th><th>原因</th><th>备注</th></tr></thead><tbody><tr><td>P0</td><td>Mermaid 多子类型</td><td>用户已有认知和现有依赖都在这里；是最低迁移成本的收益点</td><td>先把 <code>mindmap</code> 独占问题解决</td></tr><tr><td>P1</td><td>JSON Canvas</td><td>Obsidian 原生资产格式；最契合知识图谱和空间整理</td><td>不需要额外重型渲染运行时</td></tr><tr><td>P1</td><td>Vega-Lite</td><td>数值和对比类笔记的正确表达介质</td><td>需要专门 chart adapter 和预览</td></tr><tr><td>P2</td><td>HTML/SVG infographic</td><td>适合摘要卡片、KPI、路标图</td><td>价值高，但需要主题和导出能力支撑</td></tr><tr><td>P3</td><td>PlantUML / Graphviz / Draw.io</td><td>语法面大、依赖重、维护成本高</td><td>延后到渲染平台成熟后再评估</td></tr></tbody></table><h3 id="决策-4-渲染宿主优先走-iframe-host-但以渐进式打包为前提" tabindex="-1">决策 4：渲染宿主优先走 <code>iframe host</code>，但以渐进式打包为前提 <a class="header-anchor" href="#决策-4-渲染宿主优先走-iframe-host-但以渐进式打包为前提" aria-label="Permalink to &quot;决策 4：渲染宿主优先走 `iframe host`，但以渐进式打包为前提&quot;">​</a></h3><p>建议路线：</p><ul><li>第一阶段允许 <code>InlineRenderHost</code> 只服务 Mermaid 和本地 SVG 预览。</li><li>同时定义统一 <code>RenderHost</code> 接口，避免未来重构调用方。</li><li>第二阶段再上 <code>IframeRenderHost</code> 承担 Vega-Lite、HTML/SVG 信息卡和更重的前端渲染逻辑。</li></ul><p>理由：</p><ul><li>当前构建体系不适合一上来就做完整 worker/offscreen 体系。</li><li><code>iframe host</code> 足以隔离大部分前端渲染依赖，且更贴近 Obsidian 插件的现实约束。</li><li>不建议一步到位复制 <code>markdown-viewer</code> 的多宿主复杂度。Notemd 目前没有那个必要，也没有那个代码边界。</li></ul><hr><h2 id="目标模块布局" tabindex="-1">目标模块布局 <a class="header-anchor" href="#目标模块布局" aria-label="Permalink to &quot;目标模块布局&quot;">​</a></h2><p>建议新增或拆分出如下边界：</p><ul><li><code>src/diagram/types.ts</code></li><li><code>src/diagram/intent.ts</code></li><li><code>src/diagram/spec.ts</code></li><li><code>src/diagram/planner.ts</code></li><li><code>src/diagram/prompts/diagramSpecPrompt.ts</code></li><li><code>src/diagram/validators/specValidator.ts</code></li><li><code>src/diagram/adapters/mermaid/base.ts</code></li><li><code>src/diagram/adapters/mermaid/mindmapAdapter.ts</code></li><li><code>src/diagram/adapters/mermaid/flowchartAdapter.ts</code></li><li><code>src/diagram/adapters/mermaid/sequenceAdapter.ts</code></li><li><code>src/diagram/adapters/mermaid/erAdapter.ts</code></li><li><code>src/diagram/adapters/mermaid/validator.ts</code></li><li><code>src/diagram/adapters/canvas/canvasAdapter.ts</code></li><li><code>src/diagram/adapters/vega/vegaLiteAdapter.ts</code></li><li><code>src/rendering/types.ts</code></li><li><code>src/rendering/rendererRegistry.ts</code></li><li><code>src/rendering/rendererService.ts</code></li><li><code>src/rendering/cache/renderCache.ts</code></li><li><code>src/rendering/host/renderHost.ts</code></li><li><code>src/rendering/host/inlineRenderHost.ts</code></li><li><code>src/rendering/host/iframeRenderHost.ts</code></li><li><code>src/rendering/webview/index.html</code></li><li><code>src/rendering/webview/bootstrap.ts</code></li><li><code>src/rendering/webview/renderFrame.ts</code></li><li><code>src/ui/DiagramPreviewModal.ts</code></li><li><code>src/ui/components/diagramPreviewToolbar.ts</code></li></ul><p>建议逐步降责的旧文件：</p><ul><li><code>src/main.ts</code></li><li><code>src/fileUtils.ts</code></li><li><code>src/mermaidProcessor.ts</code></li><li><code>src/promptUtils.ts</code></li></ul><hr><h2 id="执行计划" tabindex="-1">执行计划 <a class="header-anchor" href="#执行计划" aria-label="Permalink to &quot;执行计划&quot;">​</a></h2><h3 id="任务-0-面向专用渲染的构建与打包底座" tabindex="-1">任务 0：面向专用渲染的构建与打包底座 <a class="header-anchor" href="#任务-0-面向专用渲染的构建与打包底座" aria-label="Permalink to &quot;任务 0：面向专用渲染的构建与打包底座&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li>现有运行时宿主：<code>src/rendering/webview/contract.ts</code></li><li>现有运行时宿主：<code>src/rendering/webview/page.ts</code></li><li>现有运行时宿主：<code>src/rendering/webview/renderFrame.ts</code></li><li>创建：<code>scripts/audit-render-host-bundle.js</code></li><li>修改：<code>package.json</code></li><li>修改：<code>.github/workflows/release.yml</code></li><li>测试：<code>src/tests/renderHostBundleAuditScript.test.ts</code></li></ul><p><strong>状态：</strong> 已交付，但限制已明确</p><p>当前已经通过 <code>src/rendering/webview/contract.ts</code>、<code>src/rendering/webview/page.ts</code>、<code>src/rendering/webview/renderFrame.ts</code> 和 <code>src/rendering/host/iframeRenderHost.ts</code> 建立了内联 <code>srcdoc</code> preview host。也就是说，“渲染页面如何被插件携带”这个问题仍然通过主 bundle 内嵌 HTML 的方式解决，而不是通过额外静态资产复制解决。</p><p>本批工作补上了真正缺失的 smoke gate：<code>scripts/audit-render-host-bundle.js</code> 会直接审计构建后的 <code>main.js</code>，要求 bundle 中仍保留 <code>htmlSrcdoc</code>、<code>Notemd Render Host</code>、<code>notemd-render-shell</code> 和 <code>notemd-html-preview-theme-shim</code> 等关键标记，并拒绝出现 <code>rendering-webview/index.html</code> 之类的外部 render-host 资产依赖；<code>.github/workflows/release.yml</code> 也已把该审计纳入 release gate。</p><p>剩余限制依然存在：<code>esbuild.config.mjs</code> 仍是单入口，当前 smoke gate 证明的是“现有 srcdoc host 自包含不退化”，不是“已经具备真正独立 heavier runtime bundle 的打包与安装策略”。</p><ul><li>[x] 明确渲染资产目录约定，避免后续把 HTML、JS、CSS 散落到插件根目录。</li><li>[x] 为生产构建固化 render host 的 bundle 携带方式，保证预览页面继续由 <code>main.js</code> 自包含发布。</li><li>[x] 建立最小 smoke 测试，验证构建产物中包含渲染页面和必要脚本。</li></ul><p><strong>决策：</strong></p><ul><li>Obsidian 标准社区插件 release 资产模型只保证 <code>main.js</code>、<code>manifest.json</code>、<code>styles.css</code>，因此不要把运行时正确性建立在“额外目录会随 release 安装下来”的假设上。</li><li>第一阶段优先使用 <code>iframe srcdoc</code> 或其他内联页面契约，把预览宿主做成 <code>main.js</code> 可携带的自包含能力，而不是依赖外部 <code>rendering-webview/</code> 目录。</li><li>如果后续确实需要更重的独立 runtime bundle，必须同时设计 release 打包与安装期落盘策略，而不是只在本地构建成功。</li><li>现阶段的 smoke gate 应当继续锁定“自包含 srcdoc host”这一约束；任何转向外部 host 资产的实现，都必须同步修改 release 资产模型、审计脚本和安装路径设计。</li></ul><p><strong>完成标准：</strong></p><ul><li>构建产物可稳定携带渲染页面，并有自动审计阻止退化为未声明的外部 host 资产依赖。</li><li>不影响当前插件加载。</li></ul><h3 id="任务-1-引入-diagram-领域模型与意图路由器" tabindex="-1">任务 1：引入 Diagram 领域模型与意图路由器 <a class="header-anchor" href="#任务-1-引入-diagram-领域模型与意图路由器" aria-label="Permalink to &quot;任务 1：引入 Diagram 领域模型与意图路由器&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li>创建：<code>src/diagram/types.ts</code></li><li>创建：<code>src/diagram/intent.ts</code></li><li>创建：<code>src/diagram/spec.ts</code></li><li>创建：<code>src/diagram/planner.ts</code></li><li>修改：<code>src/types.ts</code></li><li>测试：<code>src/tests/diagramIntent.test.ts</code></li><li>测试：<code>src/tests/diagramSpecValidation.test.ts</code></li></ul><p><strong>状态：</strong> 已交付</p><p><code>src/diagram/types.ts</code>、<code>src/diagram/spec.ts</code>、<code>src/diagram/intent.ts</code> 与 <code>src/diagram/planner.ts</code> 已经把 diagram intent、spec、validator 和 route planner 变成真实边界。当前主要问题已不再是“有没有 domain model”，而是后续所有命令是否都持续复用这套模型。</p><ul><li>[x] 定义 <code>DiagramIntent</code>，覆盖至少 <code>mindmap</code>、<code>flowchart</code>、<code>sequence</code>、<code>classDiagram</code>、<code>erDiagram</code>、<code>stateDiagram</code>、<code>canvasMap</code>、<code>dataChart</code>。</li><li>[x] 定义 <code>DiagramSpec</code> 的最小结构和 validator。</li><li>[x] 把“从笔记内容判断应输出哪类图”的逻辑从 Mermaid prompt 中剥离出来。</li></ul><p><strong>决策：</strong></p><ul><li>Intent router 先用规则 + prompt hint 的混合模式，不直接做模型级自动分类器。</li><li>当置信度不足时，默认回退到 <code>mindmap</code> 或在 UI 中让用户选择目标图种。</li></ul><p><strong>完成标准：</strong></p><ul><li>新逻辑可以在不渲染的情况下单测验证“笔记 -&gt; 意图”的判定。</li><li>Mermaid prompt 不再硬编码为唯一图种。</li></ul><h3 id="任务-2-用-spec-first-生成替代直接-mermaid-prompt" tabindex="-1">任务 2：用 Spec-First 生成替代直接 Mermaid Prompt <a class="header-anchor" href="#任务-2-用-spec-first-生成替代直接-mermaid-prompt" aria-label="Permalink to &quot;任务 2：用 Spec-First 生成替代直接 Mermaid Prompt&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li>创建：<code>src/diagram/prompts/diagramSpecPrompt.ts</code></li><li>修改：<code>src/promptUtils.ts</code></li><li>修改：<code>src/main.ts</code></li><li>测试：<code>src/tests/diagramPromptAssembly.test.ts</code></li><li>测试：<code>src/tests/diagramPlannerFlow.test.ts</code></li><li>测试：<code>src/tests/diagramCommandArchitecture.test.ts</code></li></ul><p><strong>状态：</strong> 部分完成</p><p><code>src/diagram/prompts/diagramSpecPrompt.ts</code>、<code>src/diagram/diagramSpecResponseParser.ts</code> 和 <code>src/diagram/diagramGenerationService.ts</code> 已经落地了 spec-first prompt 与 <code>spec -&gt; validate -&gt; render</code> 流水线。本批工作又把 <code>src/main.ts</code> 中三条 diagram command 的 busy-state、读取、provider 选择、error handling orchestration 收口到共享 <code>generateDiagramCommand</code>。</p><p>真正未完成的部分变成了“public surface 收口”而不是“内部完全分叉”：当前仍保留 legacy Mermaid 命令、experimental generate 命令、experimental preview 命令三个入口，以兼容既有工作流和 sidebar/custom workflow action IDs。</p><ul><li>[x] 新增“让 LLM 输出 <code>DiagramSpec</code> JSON”的 prompt。</li><li>[x] 让 <code>summarizeToMermaidCommand</code> 演进为 <code>generateDiagramCommand</code>，但保留现有命令名做兼容入口。</li><li>[x] 在服务层引入“生成 spec -&gt; 验证 spec -&gt; 交给 adapter”的流水线。</li></ul><p><strong>决策：</strong></p><ul><li>保持现有 Mermaid 命令入口可用，避免一次性破坏用户工作流。</li><li>初期允许 UI 仍显示 “Summarise as Mermaid diagram”，但内部走 diagram pipeline；后续再扩展为统一 diagram action。</li><li>命令层先统一内部 executor，再决定 public command IDs、sidebar action IDs 和 workflow DSL 是否需要迁移；否则会把兼容性问题和 orchestration 重构绑死在同一批次。</li></ul><p><strong>完成标准：</strong></p><ul><li>生成链路不再依赖 LLM 直接吐最终 Mermaid。</li><li>新的 pipeline 可以在无渲染器参与时产生可复用 spec。</li></ul><h3 id="任务-3-mermaid-adapter-v2-与-mermaidprocessor-ts-拆解" tabindex="-1">任务 3：Mermaid Adapter V2 与 <code>mermaidProcessor.ts</code> 拆解 <a class="header-anchor" href="#任务-3-mermaid-adapter-v2-与-mermaidprocessor-ts-拆解" aria-label="Permalink to &quot;任务 3：Mermaid Adapter V2 与 `mermaidProcessor.ts` 拆解&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li>创建：<code>src/diagram/adapters/mermaid/base.ts</code></li><li>创建：<code>src/diagram/adapters/mermaid/mindmapAdapter.ts</code></li><li>创建：<code>src/diagram/adapters/mermaid/flowchartAdapter.ts</code></li><li>创建：<code>src/diagram/adapters/mermaid/sequenceAdapter.ts</code></li><li>创建：<code>src/diagram/adapters/mermaid/erAdapter.ts</code></li><li>创建：<code>src/diagram/adapters/mermaid/validator.ts</code></li><li>修改：<code>src/mermaidProcessor.ts</code></li><li>测试：<code>src/tests/mermaidMindmapAdapter.test.ts</code></li><li>测试：<code>src/tests/mermaidFlowchartAdapter.test.ts</code></li><li>测试：<code>src/tests/mermaidValidator.test.ts</code></li></ul><p><strong>状态：</strong> 部分完成</p><p>Mermaid subtype adapters 已经覆盖 <code>mindmap</code>、<code>flowchart</code>、<code>sequenceDiagram</code>、<code>classDiagram</code>、<code>erDiagram</code>、<code>stateDiagram-v2</code>，并且 renderer 侧会先走 <code>mermaid.parse</code> 校验。这一批工作的价值已经兑现。</p><p>最新进展是，部分原本依赖 legacy fixer 的语法保护已经开始前移到 adapter：例如 flowchart edge label 内的 <code>|</code> 现在会在 <code>src/diagram/adapters/mermaid/flowchartAdapter.ts</code> 中直接转义为 <code>&amp;#124;</code>，而不是等 <code>fixMermaidPipes</code> 一类全局修补去救火。</p><p>但 roadmap 原本更激进的目标还没完成：<code>src/mermaidProcessor.ts</code> 仍然是大型 legacy fixer，更多 adapter-specific fix 规则还没有真正成为主路径。当前现实是“adapter-driven emit + validate 已经存在，局部语法防御开始前移，部分通用保护逻辑、note directive parsing、edge-label attachment、edge-label merge/quote/rewrite 与 note-node formatting 已下沉到 <code>src/diagram/adapters/mermaid/legacyFixerUtils.ts</code>，fixer decomposition 仍未完成”。</p><ul><li>[ ] 将 Mermaid 修复逻辑从“全局文本修补”拆成“按图种 adapter 的 emit + validate + fix”。</li><li>[ ] 把 <code>mermaidProcessor.ts</code> 中通用能力下沉为有限工具函数，把图种特定规则挪进对应 adapter。</li><li>[ ] 保留批量修复能力，但只作为 legacy fallback，不再作为主生成路径的必要步骤。</li><li>[x] 将 flowchart pipe-label 转义从 legacy fixer 前移到 adapter emit 阶段。</li><li>[x] 将 bracket-block protect/restore 这类通用 legacy fixer 机制下沉到共享工具函数，避免在 <code>fixMermaidPipes</code> 与 <code>fixMalformedArrows</code> 中重复实现。</li><li>[x] 将 targeted note 内容清洗与 note-node line formatting 下沉到共享工具函数，减少 <code>fixNotesToNodes</code> / <code>fixTargetedNotes</code> 内部重复拼接逻辑。</li><li>[x] 将 directional / for-of / standalone / targeted note directive parsing 与 directional edge-label attachment 下沉到共享工具函数，减少 <code>fixMermaidNotes</code>、<code>fixNotesToNodes</code>、<code>fixTargetedNotes</code> 内的重复正则与 string surgery。</li><li>[x] 将 double-arrow merge、unquoted edge-label quote、quoted-label-after-semicolon rewrite 下沉到共享工具函数，减少 <code>fixDoubleArrowLabels</code>、<code>fixUnquotedEdgeLabels</code>、<code>fixQuotedLabelsAfterSemicolon</code> 内的重复 line-regex surgery。</li></ul><p><strong>决策：</strong></p><ul><li>只保留最小修复策略，例如 fence 修复、少量保底字符清理。</li><li>删除“把所有括号删除”这类全局粗暴规则，避免损伤合法 Mermaid 语法。</li></ul><p><strong>完成标准：</strong></p><ul><li>至少支持 <code>mindmap</code>、<code>flowchart</code>、<code>sequenceDiagram</code>、<code>erDiagram</code> 四类 Mermaid 输出。</li><li>新生成结果对 <code>mermaid.parse</code> 的通过率显著提升。</li></ul><h3 id="任务-4-具备-registry、host、cache-与-preview-的渲染平台骨架" tabindex="-1">任务 4：具备 Registry、Host、Cache 与 Preview 的渲染平台骨架 <a class="header-anchor" href="#任务-4-具备-registry、host、cache-与-preview-的渲染平台骨架" aria-label="Permalink to &quot;任务 4：具备 Registry、Host、Cache 与 Preview 的渲染平台骨架&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li>创建：<code>src/rendering/types.ts</code></li><li>创建：<code>src/rendering/rendererRegistry.ts</code></li><li>创建：<code>src/rendering/rendererService.ts</code></li><li>创建：<code>src/rendering/cache/renderCache.ts</code></li><li>创建：<code>src/rendering/host/renderHost.ts</code></li><li>创建：<code>src/rendering/host/inlineRenderHost.ts</code></li><li>创建：<code>src/ui/DiagramPreviewModal.ts</code></li><li>修改：<code>src/main.ts</code></li><li>修改：<code>src/ui/NotemdSidebarView.ts</code></li><li>修改：<code>src/ui/NotemdSettingTab.ts</code></li><li>测试：<code>src/tests/rendererRegistry.test.ts</code></li><li>测试：<code>src/tests/rendererService.test.ts</code></li><li>测试：<code>src/tests/diagramPreviewModal.test.ts</code></li></ul><p><strong>状态：</strong> 已交付</p><p><code>RendererRegistry</code>、<code>RendererService</code>、<code>RenderCache</code>、<code>InlineRenderHost</code>、<code>IframeRenderHost</code> 与 <code>DiagramPreviewModal</code> 已经把 preview/render/export 的最小平台骨架拉起来。缓存 key 也已经纳入 <code>spec + target + theme</code>。</p><ul><li>[x] 先建立平台接口，再逐步接入真实重型 renderer。</li><li>[x] 为当前 Mermaid 输出提供统一预览入口，而不是把预览逻辑散在业务命令里。</li><li>[x] 增加简单缓存，至少按 <code>spec + target + theme</code> 做 cache key。</li></ul><p><strong>决策：</strong></p><ul><li>第一阶段的预览只要求“可打开、可刷新、可复制源码、可保存结果”，不追求导出全家桶。</li><li>缓存策略先以内存或 vault 内轻量缓存为主，不急于做复杂持久化索引。</li></ul><p><strong>完成标准：</strong></p><ul><li>调用方通过 <code>RendererService</code> 访问渲染能力，而不是直接耦合 Mermaid API。</li><li>Mermaid 预览已进入统一平台路径。</li></ul><h3 id="任务-5-将-json-canvas-作为首个非-mermaid-输出" tabindex="-1">任务 5：将 JSON Canvas 作为首个非 Mermaid 输出 <a class="header-anchor" href="#任务-5-将-json-canvas-作为首个非-mermaid-输出" aria-label="Permalink to &quot;任务 5：将 JSON Canvas 作为首个非 Mermaid 输出&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li>创建：<code>src/diagram/adapters/canvas/canvasAdapter.ts</code></li><li>创建：<code>src/diagram/adapters/canvas/layout.ts</code></li><li>修改：<code>src/fileUtils.ts</code></li><li>修改：<code>src/main.ts</code></li><li>测试：<code>src/tests/canvasAdapter.test.ts</code></li><li>测试：<code>src/tests/canvasLayout.test.ts</code></li></ul><p><strong>状态：</strong> 已按基线范围交付</p><p><code>.canvas</code> 输出、基础 deterministic layout、保存和 preview/export 支持都已落地。当前实现仍然是初始自动布局，不提供复杂回写语义，但这正符合本任务原始 scope。</p><ul><li>[x] 增加 <code>.canvas</code> 目标格式输出。</li><li>[x] 先支持知识图、概念图、研究梳理和任务拆解场景，不追求完整手工编辑语义。</li><li>[x] 支持从 <code>DiagramSpec</code> 映射到 node/edge/position 的基础布局。</li></ul><p><strong>决策：</strong></p><ul><li>初始布局可采用 deterministic auto-layout，不必一开始支持复杂拖拽回写。</li><li>Canvas 是原生资产，应优先打通保存、打开和 vault 关联流程。</li></ul><p><strong>完成标准：</strong></p><ul><li>用户可以从同一条 diagram pipeline 输出 <code>.canvas</code> 文件。</li><li>输出的 canvas 在 Obsidian 中可直接打开。</li></ul><h3 id="任务-6-为数值与对比型笔记增加-vega-lite" tabindex="-1">任务 6：为数值与对比型笔记增加 Vega-Lite <a class="header-anchor" href="#任务-6-为数值与对比型笔记增加-vega-lite" aria-label="Permalink to &quot;任务 6：为数值与对比型笔记增加 Vega-Lite&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li>创建：<code>src/diagram/adapters/vega/vegaLiteAdapter.ts</code></li><li>创建：<code>src/diagram/adapters/vega/schema.ts</code></li><li>创建：<code>src/rendering/host/iframeRenderHost.ts</code></li><li>修改：<code>src/rendering/webview/bootstrap.ts</code></li><li>修改：<code>src/rendering/webview/renderFrame.ts</code></li><li>测试：<code>src/tests/vegaLiteAdapter.test.ts</code></li><li>测试：<code>src/tests/iframeRenderHost.test.ts</code></li></ul><p><strong>状态：</strong> 部分完成</p><p><code>dataChart</code> intent、controlled Vega-Lite templates、planner chart defaults、preview/export 和 HTML fallback 都已落地，说明“数值与对比类笔记不必再被 Mermaid 强塞”这个产品方向已经成立。</p><p>真正还没完成的是 runtime boundary：当前 <code>IframeRenderHost</code> 更多承担 preview session / <code>srcdoc</code> 外壳职责，Vega-Lite SVG 渲染仍通过 <code>src/rendering/preview/vegaLitePreview.ts</code> 在插件 runtime 内动态加载 <code>vega-lite</code> 与 <code>vega</code>。所以“Vega-Lite 已支持”成立，但“已通过 iframe host 隔离渲染依赖”还不能算完成。</p><ul><li>[x] 让包含明确数据点、序列、对比、占比的笔记走 <code>dataChart</code> intent。</li><li>[ ] 通过 iframe host 隔离 Vega-Lite 渲染依赖。</li><li>[x] 先支持 bar、line、area、scatter、pie、table-like summary 六类高价值图表模板。</li></ul><p><strong>决策：</strong></p><ul><li>不支持“模型自由发挥写任意 Vega 规范”；只支持受控子集和模板化 schema。</li><li>图表生成必须要求明确数据来源，避免编造数值。</li></ul><p><strong>完成标准：</strong></p><ul><li>Vega-Lite 成为正式受支持的非 Mermaid 可预览输出。</li><li>渲染失败可回退到 spec/source JSON，而不是直接吞错。</li></ul><h3 id="任务-7-主题、导出与发布加固" tabindex="-1">任务 7：主题、导出与发布加固 <a class="header-anchor" href="#任务-7-主题、导出与发布加固" aria-label="Permalink to &quot;任务 7：主题、导出与发布加固&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li>修改：<code>src/rendering/rendererService.ts</code></li><li>修改：<code>src/ui/DiagramPreviewModal.ts</code></li><li>修改：<code>styles.css</code></li><li>修改：<code>README.md</code></li><li>修改：<code>docs/releases/*.md</code></li><li>测试：<code>src/tests/renderThemeConfig.test.ts</code></li><li>测试：<code>src/tests/renderExportFlow.test.ts</code></li></ul><p><strong>状态：</strong> 已交付，且支持边界已明确</p><p>当前代码已经把 preview/export 的主题解析、UI locale 文案、SVG/PNG/source 导出与 README/release docs 对齐。需要强调的是：这不是“所有 target 一视同仁地支持所有导出”，而是“支持矩阵已被显式化”。HTML 目标当前只承诺 iframe fallback preview 和 raw source save，这一点应继续保持文档与实现一致。</p><ul><li>[x] 将 UI 语言、Obsidian theme、图表主题和导出选项对齐。</li><li>[x] 补齐 PNG、SVG、source JSON/canvas 导出。</li><li>[x] 更新文档，明确支持图种、限制、降级策略和故障排查。</li></ul><p><strong>决策：</strong></p><ul><li>先支持导出最稳定的格式组合，避免一开始承诺 PDF、DOCX、批量快照等高维护能力。</li><li>文档里要明确哪些输出是“生成文件”，哪些是“可预览渲染结果”。</li></ul><p><strong>完成标准：</strong></p><ul><li>用户可以预览、复制源码、导出至少一种图像结果。</li><li>语言、主题和图种支持矩阵文档化。</li></ul><h3 id="任务-8-已延后的高级引擎评估" tabindex="-1">任务 8：已延后的高级引擎评估 <a class="header-anchor" href="#任务-8-已延后的高级引擎评估" aria-label="Permalink to &quot;任务 8：已延后的高级引擎评估&quot;">​</a></h3><p><strong>文件：</strong></p><ul><li>若批准后再创建：<code>src/diagram/adapters/plantuml/*</code></li><li>若批准后再创建：<code>src/diagram/adapters/graphviz/*</code></li><li>后续再测试：<code>src/tests/plantumlAdapter.test.ts</code></li></ul><p><strong>状态：</strong> 延后策略正确</p><p>这一段目前没有落后，反而是最需要坚持的边界。现状的真正短板不是格式不够多，而是 build/runtime isolation、command 收口、legacy Mermaid 退场边界还不够硬。如果现在引入 PlantUML、Graphviz 或 Draw.io，只会把未完成的平台债扩散到更多 DSL 上。</p><ul><li>[ ] 仅在前述平台完成后评估 PlantUML、Graphviz、Draw.io。</li><li>[ ] 先做需求证据收集，再决定是否进入实现。</li></ul><p><strong>决策门槛：</strong></p><ul><li>只有当以下条件同时成立时才进入： <ul><li>Renderer platform 已稳定。</li><li>现有 Mermaid/Canvas/Vega-Lite 已覆盖大部分需求。</li><li>用户有明确场景需要更专业 DSL。</li><li>有清晰的渲染与分发策略，而不是“先生成代码再说”。</li></ul></li></ul><hr><h2 id="短中长期方向控制" tabindex="-1">短中长期方向控制 <a class="header-anchor" href="#短中长期方向控制" aria-label="Permalink to &quot;短中长期方向控制&quot;">​</a></h2><h3 id="短期" tabindex="-1">短期 <a class="header-anchor" href="#短期" aria-label="Permalink to &quot;短期&quot;">​</a></h3><p>目标周期：紧随当前 <code>main</code> 的下一批 diagram-platform 收口工作</p><p>重点：</p><ul><li>维持任务 0 已交付的 render-host smoke gate，不允许后续运行时迭代绕过发布/安装约束</li><li>完成任务 2 中真正缺失的命令架构收口，减少 legacy 命令与 experimental 命令长期双轨</li><li>完成任务 3 中真正缺失的 <code>mermaidProcessor.ts</code> 降责和 sunset boundary</li><li>明确任务 6 中 Vega-Lite 运行时应该继续留在插件运行时，还是转入真正的 bundled host 资产</li></ul><p>成功标志：</p><ul><li>下一批工作不再误把“加更多 renderer”当成主问题。</li><li>best-fit / legacy-mermaid 的边界更清晰，experimental 标签不再掩盖真实状态。</li><li><code>src/main.ts</code> 不继续成为 diagram orchestration 的永久扩张点。</li></ul><h3 id="中期" tabindex="-1">中期 <a class="header-anchor" href="#中期" aria-label="Permalink to &quot;中期&quot;">​</a></h3><p>目标周期：<code>1.9.x</code></p><p>重点：</p><ul><li>将 JSON Canvas 与 Vega-Lite 从“功能已存在”推进到“默认可理解、稳定可维护”的产品面</li><li>落定 heavier renderer runtime 的打包与运行策略</li><li>评估 HTML/SVG infographic 是否应作为正式 target，而不是仅做 fallback</li><li>把 docs、tests、release notes 和 support matrix 绑定到同一套 truth source</li></ul><p>成功标志：</p><ul><li>experimental diagram 功能不再依赖过多 maintainer-only 上下文才能理解。</li><li>非 Mermaid 输出不只是“能生成”，而是具备可解释的稳定边界和故障模型。</li><li>文档对现状与限制的描述不再滞后于代码。</li></ul><h3 id="长期" tabindex="-1">长期 <a class="header-anchor" href="#长期" aria-label="Permalink to &quot;长期&quot;">​</a></h3><p>目标周期：<code>2.0+</code></p><p>重点：</p><ul><li>在 host/runtime boundary 完整成立后，再评估 richer infographic targets</li><li>在 support matrix 和 release discipline 成熟后，再评估 PlantUML、Graphviz 等重型 DSL</li><li>评估统一 diagram workspace、批量渲染和资产索引</li></ul><p>成功标志：</p><ul><li>图形平台成为独立能力域，而不是附属于某个单一命令。</li><li>具备明确的 target support matrix、theme contract、render failure model 和 release discipline。</li></ul><hr><h2 id="关键风险与控制方式" tabindex="-1">关键风险与控制方式 <a class="header-anchor" href="#关键风险与控制方式" aria-label="Permalink to &quot;关键风险与控制方式&quot;">​</a></h2><h3 id="风险-过早引入太多图种-平台没有抽象先失控" tabindex="-1">风险：过早引入太多图种，平台没有抽象先失控 <a class="header-anchor" href="#风险-过早引入太多图种-平台没有抽象先失控" aria-label="Permalink to &quot;风险：过早引入太多图种，平台没有抽象先失控&quot;">​</a></h3><p>控制策略：</p><ul><li>先实现平台接口和前两类非 Mermaid 目标。</li><li>每新增一个目标格式，都必须复用 <code>DiagramSpec</code> 和 <code>RendererService</code>。</li></ul><h3 id="风险-把-markdown-viewer-extension-整体搬进来-复杂度超出-notemd-当前承载能力" tabindex="-1">风险：把 <code>markdown-viewer-extension</code> 整体搬进来，复杂度超出 Notemd 当前承载能力 <a class="header-anchor" href="#风险-把-markdown-viewer-extension-整体搬进来-复杂度超出-notemd-当前承载能力" aria-label="Permalink to &quot;风险：把 `markdown-viewer-extension` 整体搬进来，复杂度超出 Notemd 当前承载能力&quot;">​</a></h3><p>控制策略：</p><ul><li>只借鉴其 registry/host/cache 设计思想。</li><li>不照搬 offscreen、多端桥接、DOCX 导出和全部 renderer 集。</li></ul><h3 id="风险-vega-lite-或-html-heavier-runtime-演进再次偷偷引入未声明的外部-host-资产依赖" tabindex="-1">风险：Vega-Lite 或 HTML heavier runtime 演进再次偷偷引入未声明的外部 host 资产依赖 <a class="header-anchor" href="#风险-vega-lite-或-html-heavier-runtime-演进再次偷偷引入未声明的外部-host-资产依赖" aria-label="Permalink to &quot;风险：Vega-Lite 或 HTML heavier runtime 演进再次偷偷引入未声明的外部 host 资产依赖&quot;">​</a></h3><p>控制策略：</p><ul><li>保持第一阶段 host 自包含在 <code>main.js</code> 内，并用 bundle smoke gate 持续审计。</li><li>如果必须引入独立 host 资产，先定义 release 打包、安装落盘和 capability fallback，再改实现。</li></ul><h3 id="风险-生成-spec-时模型臆造数据" tabindex="-1">风险：生成 spec 时模型臆造数据 <a class="header-anchor" href="#风险-生成-spec-时模型臆造数据" aria-label="Permalink to &quot;风险：生成 spec 时模型臆造数据&quot;">​</a></h3><p>控制策略：</p><ul><li>对 <code>dataChart</code> 强制要求 evidence/data extraction 步骤。</li><li>没有明确数值时，只允许生成结构图或文本摘要卡，不允许编造图表。</li></ul><h3 id="风险-继续保留过多-legacy-fallback-最终双系统长期共存" tabindex="-1">风险：继续保留过多 legacy fallback，最终双系统长期共存 <a class="header-anchor" href="#风险-继续保留过多-legacy-fallback-最终双系统长期共存" aria-label="Permalink to &quot;风险：继续保留过多 legacy fallback，最终双系统长期共存&quot;">​</a></h3><p>控制策略：</p><ul><li>给旧 Mermaid 修补链设置 sunset 边界。</li><li>每完成一个 adapter，就减少一部分 legacy fixer 责任，而不是无限共存。</li></ul><hr><h2 id="反目标" tabindex="-1">反目标 <a class="header-anchor" href="#反目标" aria-label="Permalink to &quot;反目标&quot;">​</a></h2><p>以下方向当前不应进入主线：</p><ul><li>直接支持 raster AI 绘图或图片生成</li><li>一开始就做 Draw.io round-trip 编辑</li><li>在没有 renderer runtime 的前提下承诺“支持很多图表类型”</li><li>为 PlantUML/Graphviz 引入需要额外服务端或复杂 license 风险的路径</li><li>在 <code>src/main.ts</code> 中继续堆叠新的图形业务逻辑</li></ul><hr><h2 id="建议的下一批工作" tabindex="-1">建议的下一批工作 <a class="header-anchor" href="#建议的下一批工作" aria-label="Permalink to &quot;建议的下一批工作&quot;">​</a></h2><p>如果现在继续推进，建议只做“收口批次”，不要回到“先加更多 target 再说”的路径：</p><ol><li>完成任务 2 剩余部分：diagram command architecture 收口</li><li>完成任务 3 剩余部分：<code>mermaidProcessor.ts</code> 降责与 legacy fixer sunset boundary</li><li>完成任务 6 剩余部分：决定 Vega-Lite heavier runtime 的真正宿主边界</li><li>继续维护任务 7：把 support matrix 与 release/docs contract 绑定得更硬</li><li>把任务 0 的 smoke gate 当成回归边界，后续若引入独立 host 资产必须先升级 release/install 设计</li></ol><p>原因很直接：</p><ul><li>当前的关键断点已经不是“有没有 DiagramSpec/renderer registry”，而是“这些能力是否已经被正确 productize”。</li><li>如果这一断点没完成，后续任何新 renderer 都会继续叠在未完成的 runtime/command/legacy 边界上，返工成本只会更高。</li></ul><hr><h2 id="每个阶段的验证门禁" tabindex="-1">每个阶段的验证门禁 <a class="header-anchor" href="#每个阶段的验证门禁" aria-label="Permalink to &quot;每个阶段的验证门禁&quot;">​</a></h2><p>每个阶段都应至少具备以下验证：</p><ul><li><code>npm run build</code></li><li>目标单元测试通过</li><li><code>npm run audit:render-host</code></li><li>当前 Mermaid 回归集通过</li><li>新 renderer 的失败场景有明确错误面</li><li>产物路径、预览入口和导出结果可人工验证</li></ul><p>对于渲染层新增功能，补充要求：</p><ul><li>至少一条桌面端预览验证记录</li><li>至少一条移动端或降级策略验证记录</li><li>文档同步更新支持矩阵和限制说明</li></ul><hr><h2 id="最终建议" tabindex="-1">最终建议 <a class="header-anchor" href="#最终建议" aria-label="Permalink to &quot;最终建议&quot;">​</a></h2><p>最佳推进方向不是“继续强化 Mermaid 修补”，也不是“直接上十几个图种”，而是：</p><p>先把已经存在的 diagram platform productize，再决定它应该再承载哪些 renderer。</p><p>如果要用一句话概括接下来的技术策略，就是：</p><p><code>spec-first, adapter-driven, productized boundaries before expansion</code></p>',218)])])}const u=r(t,[["render",o]]);export{g as __pageData,u as default};
